window.__DATA_POSTS = {"posts": [{"id": "p001", "author": "char_lea", "text": "Erster Kaffee hier. Überraschung: der dünnste Filterkaffee der Welt.", "tags": ["lifestyle", "humor"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p002", "author": "char_finn", "text": "Gestern auf Platin gerankt. Meine Mutter: „Geh schlafen.“ Mein Ruhm: kurz.", "tags": ["gaming", "humor"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p003", "author": "char_jule", "text": "Playlist „Regen in Greifshafen“ ist online. Fünf Songs. Eine Stimmung.", "tags": ["musik", "lifestyle"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p004", "author": "char_mira", "text": "Radweg in der Innenstadt wird endlich erweitert. Demo gestern war klein, aber laut — und es hat gewirkt.", "tags": ["politik-links", "klima", "lifestyle"], "engagement_bait_score": 0.4, "outrage_score": 0.2, "political_lean": -0.4, "quality_score": 0.6}, {"id": "p005", "author": "char_tariq", "text": "Mini-Fakt: Der „Mond wirkt größer am Horizont“-Effekt ist optisch. Tatsächlich ist er sogar etwas weiter weg.", "tags": ["wissenschaft", "humor"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.8}, {"id": "p006", "author": "char_moritz", "text": "Yo, neue Leute: wer ist von euch in der Klasse 12b?", "tags": ["lifestyle", "humor"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.4}, {"id": "p007", "author": "char_sara", "text": "Habe den ersten Arm meines Projektroboters zum Laufen gebracht. Sie winkt. Das ist alles. 🤖", "tags": ["wissenschaft", "gaming"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.7}, {"id": "p008", "author": "char_ana", "text": "Samstag: DJ-Set im ZEK (Zentrum für elektronische Kunst, Ostufer), 23 Uhr. Erstes Mal Greifshafen, House- und Breakbeat-lastig, ein paar unveröffentlichte Sachen dabei. Kommt, wenn ihr wollt.", "tags": ["musik", "lifestyle"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p009", "author": "char_nele", "text": "„Die unsichtbaren Mechanismen“ von K. Özdemir — liest sich wie ein Thriller über Plattformen. Klare Empfehlung. Ein Kapitel über Empfehlungssysteme hat mich nicht mehr schlafen lassen — weil ich gemerkt habe, wie lange ich schon nicht mehr entscheide, was ich sehe.", "tags": ["lifestyle", "wissenschaft"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": -0.1, "quality_score": 0.7, "article": {"kicker": "Buch-Ausschnitt · Kapitel 3", "title": "Die unsichtbaren Mechanismen", "excerpt": "„Ein Feed ist keine Zeitung. Er wird nicht am Abend gedruckt, sondern in dem Moment, in dem du ihn ansiehst — neu, für dich, und nur für dich. Wer das versteht, versteht, warum zwei Menschen, die nebeneinandersitzen, über dieselbe Stadt reden und sich dabei fremd werden.“", "source": "K. Özdemir · Hanser Verlag", "date": "2027"}}, {"id": "p010", "author": "char_lea", "text": "Neue Klasse: zwei bekannte Gesichter, drei neue Namen, ein Hund am Fenster. Läuft.", "tags": ["lifestyle", "humor"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p011", "author": "char_finn", "text": "Unpopular Opinion: Patch 4.7 für Battlerunes ist gut. Ja, der Support-Nerf tut weh (−15 % Heal-Radius), und die Ranked-Queue ist grad ein Alptraum. Aber: Jungle-Timer endlich gefixt, Mages oneshotten nicht mehr aus der Fog, und der neue Map-Flow im Ostabschnitt macht obere Lane spielbar. Fight me.", "tags": ["gaming", "humor"], "engagement_bait_score": 0.6, "outrage_score": 0.2, "political_lean": 0.0, "quality_score": 0.4, "replies": [{"text": "„Endlich schießt die Meta nicht mehr nur die obere Lane.", "type": "comment"}, {"text": "„Nee. Sie haben den Support generft, erklär mir das.", "type": "angry_comment"}, {"text": "„Fight you? Lobby auf, ich komme.", "type": "comment"}, {"text": "„Finn verteidigt wirklich jedes Patch. Jedes.", "type": "comment"}]}, {"id": "p012", "author": "char_tariq", "text": "Warum sind Wolken weiß? Streuung. Ernsthaft. Das ist der ganze Zauber.", "tags": ["wissenschaft", "humor"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.8}, {"id": "p013", "author": "char_jule", "text": "Popkultur-Take: die 2010er kommen zurück. Skinny Jeans im Schaufenster, Indie Sleaze auf jeder zweiten Party-Playlist, Tumblr-Filter in neuen Foto-Apps, Arctic-Monkeys-Shirts in frischer Auflage. Nicht fragen warum. Einfach hinnehmen.", "tags": ["lifestyle", "musik", "humor"], "engagement_bait_score": 0.4, "outrage_score": 0.1, "political_lean": 0.0, "quality_score": 0.4}, {"id": "p014", "author": "char_mira", "text": "Kurz zur Studie von gestern: sie sagt NICHT, dass individueller Verzicht nichts bringt — sondern, dass Strukturen wichtiger sind. Differenzieren lohnt sich. Die Überschriften machen daraus „Verzicht bringt nichts“, was ein Ding ist, das niemand in der Studie sagt. Screenshot ist im Thread.", "tags": ["klima", "wissenschaft", "politik-links"], "engagement_bait_score": 0.4, "outrage_score": 0.2, "political_lean": -0.4, "quality_score": 0.7, "article": {"kicker": "Studien-Ausschnitt · PIK, S. 14", "title": "Strukturelle vs. individuelle Klimamaßnahmen", "excerpt": "„Individuelle Konsumentscheidungen tragen messbar, aber klein bei (ca. 6–14 % der vermeidbaren Emissionen). Der größere Hebel liegt in Infrastrukturentscheidungen, Energiemix und Regulierung. Beides ist nötig; gegen­einander ausspielen verkürzt die Debatte.“", "source": "Potsdam-Institut für Klimafolgenforschung", "date": "03/2028"}, "replies": [{"text": "„Das hätte man in der Tagesschau so sagen müssen.", "type": "comment"}, {"text": "„Link zur Studie, bitte?", "type": "comment"}, {"text": "„Dann lasst doch mal das Moralisieren.", "type": "angry_comment"}, {"text": "„Mira, danke — ich teil das in meiner Klasse.", "type": "comment"}]}, {"id": "p015", "author": "char_sophia", "text": "Die Studie der Uni Tübingen zu Medienkonsum bei 14- bis 19-Jährigen (n ≈ 2.800, Längsschnitt über drei Jahre) ist solide. Kernbefund: Nicht die reine Bildschirmzeit korreliert mit Wohlbefinden, sondern Art der Inhalte und ob aktiv interagiert oder passiv gescrollt wird. Die Überschriften dazu („Handy macht Jugend depressiv“): meistens nicht.", "tags": ["wissenschaft"], "engagement_bait_score": 0.3, "outrage_score": 0.1, "political_lean": -0.1, "quality_score": 0.9}, {"id": "p016", "author": "char_greif", "text": "Stadt Greifshafen — Radwegerweiterung startet im Mai. Einwohnerinformationen in der Rathaus-App.", "tags": ["politik-mitte", "klima"], "engagement_bait_score": 0.1, "outrage_score": 0.0, "political_lean": 0.05, "quality_score": 0.8}, {"id": "p017", "author": "char_noah", "text": "Frage in die Runde: Wie würdet ihr „Freiheit“ definieren, ohne dass es ein T-Shirt-Slogan wird?", "tags": ["politik-mitte", "wissenschaft"], "engagement_bait_score": 0.5, "outrage_score": 0.1, "political_lean": 0.0, "quality_score": 0.6}, {"id": "p018", "author": "char_bens", "text": "Ich frage nur: wer zahlt eigentlich für all die Studien, die uns sagen, was wir denken sollen? „Neutrale Forschung“ gibt's nicht, wenn 80 % der Gelder aus denselben Töpfen kommen. Schaut euch die Gutachter an, dann versteht ihr das Spiel. Ich sag nur: Follow the money.", "tags": ["verschwoerung", "politik-rechts"], "engagement_bait_score": 0.85, "outrage_score": 0.6, "political_lean": 0.6, "quality_score": 0.2, "replies": [{"text": "„Endlich sagt's einer.", "type": "comment"}, {"text": "„Kannst du die Töpfe bitte konkret nennen?", "type": "comment"}, {"text": "„Follow the money heißt auch: schau dir deine Abos an.", "type": "angry_comment"}, {"text": "„Bens, du redest Unsinn.", "type": "angry_comment"}]}, {"id": "p019", "author": "char_lea", "text": "Die erste Runde Brückenbier mit den neuen Leuten. War gut. Selten gut.", "tags": ["lifestyle", "humor"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p020", "author": "char_ana", "text": "Studio-Tag war lang. Ein Track ist fast fertig. Klingt wie Herbst klingen sollte.", "tags": ["musik", "lifestyle"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p021", "author": "char_finn", "text": "Solo-Queue-Frustration in Battlerunes ist real — sieben Matches, fünf Leaver, zwei Flamer. Aber ich bin halt selbst schuld, weil ich bei 1 Uhr morgens noch eine Runde anfange.", "tags": ["gaming", "humor"], "engagement_bait_score": 0.3, "outrage_score": 0.2, "political_lean": 0.0, "quality_score": 0.4}, {"id": "p022", "author": "char_jule", "text": "Album-Rezension zu „Nachtfähre“ von Ilvy Koch online — drittes Album, düsterer als die ersten beiden, viel Synth, wenig Hymnen, ein Track („Hafenmole“) macht fast alles auf dem Album wett (Link im Bio, ja, altmodisch, ich weiß).", "tags": ["musik", "lifestyle"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p023", "author": "char_tariq", "text": "Die meisten „KI kann jetzt X“-Posts sind falsch. KI kann jetzt X annähern und dabei sehr überzeugend aussehen.", "tags": ["wissenschaft"], "engagement_bait_score": 0.3, "outrage_score": 0.1, "political_lean": 0.0, "quality_score": 0.8}, {"id": "p024", "author": "char_mira", "text": "„Klimaschutz spaltet“ — nein. Die, die das sagen, spalten. Der Klimawandel ist messbar, nicht verhandelbar.", "tags": ["klima", "politik-links"], "engagement_bait_score": 0.6, "outrage_score": 0.4, "political_lean": -0.6, "quality_score": 0.6}, {"id": "p025", "author": "char_nele", "text": "Lokal-Tipp: Buchhandlung an der Fleetmarktkante. Und ja, das Café dahinter hat guten Kakao.", "tags": ["lifestyle"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.6}, {"id": "p026", "author": "char_bens", "text": "Was die Medien dir NICHT erzählen wollen: In der Kommune werden Gelder verschoben — Quelle habe ich, Doku kommt. Ein interner Vermerk, den mir ein mutiger Mitarbeiter (danke!) zugespielt hat, zeigt: über 1,2 Mio. € laufen über einen Topf, über den kein Stadtrat abstimmt. Lokalpresse? Schweigt. Rathaus? Schweigt. WIR schweigen nicht.", "tags": ["verschwoerung", "politik-rechts"], "engagement_bait_score": 0.95, "outrage_score": 0.75, "political_lean": 0.55, "quality_score": 0.15, "article": {"kicker": "„Geleakter Vermerk“ (Screenshot-Ausschnitt)", "title": "Haushaltsposten K-17 / Sondervermögen", "excerpt": "„Zuweisung in Höhe von 1.247.000 € aus der Kategorie K-17 (‚Strukturmittel, projektbezogen‘). Auszahlung gebündelt an Zweckverband „Stadtforum Greifshafen gGmbH“. Verwendungsnachweis nach § 23 GemHVO ausstehend.“\n\n[Hinweis der Redaktion dieses Posts: Herkunft und Echtheit des Dokuments sind nicht geprüft.]", "source": "Unbenannte Quelle", "date": "angeblich Q1 / 2028"}, "replies": [{"text": "„Krass. Ich teile das sofort.", "type": "comment"}, {"text": "„‚Herkunft nicht geprüft‘ — das ist der ganze Post.", "type": "comment"}, {"text": "„Das ist Rufmord ohne Beweise.", "type": "angry_comment"}, {"text": "„Ich warte auf die Doku, Bens.", "type": "comment"}]}, {"id": "p027", "author": "char_fem", "text": "Equal Pay Day 2028: 6. März. Heißt: Frauen haben bis dahin gegenüber Männern umsonst gearbeitet. Unbereinigter Gender Pay Gap weiterhin 18 %, bereinigt 6 % — und „bereinigt“ ist kein Freispruch, sondern eine Rechenübung, die Teilzeit, Branche und Care-Arbeit einfach wegkürzt. Die Zahlen sind wieder da. Wir reden nochmal.", "tags": ["feminismus", "politik-links"], "engagement_bait_score": 0.5, "outrage_score": 0.3, "political_lean": -0.5, "quality_score": 0.6}, {"id": "p028", "author": "char_redpill", "text": "Männer: Niemand kommt euch retten. Kaltes Wasser. 5 Uhr aufstehen. Kein Zucker. Kein Weinen. So wird aus Jungen etwas. Stay hard. Stay based. Das Programm gibt's für 99 € auf meiner Seite. Erste 100 Plätze, bis Sonntag.", "tags": ["anti-feminismus", "politik-rechts", "lifestyle"], "engagement_bait_score": 0.85, "outrage_score": 0.45, "political_lean": 0.6, "quality_score": 0.2, "replies": [{"text": "„Marc, genau die Energie brauche ich.", "type": "comment"}, {"text": "„Kein Weinen? Das ist Schaden, nicht Stärke.", "type": "comment"}, {"text": "„99 € für Parolen. Bitte nicht.", "type": "angry_comment"}, {"text": "„Kaltes Wasser ist ok. Der Rest ist Verkauf.", "type": "comment"}]}, {"id": "p029", "author": "char_sara", "text": "Mathe-Hausaufgabe an alle: Wenn 1 Person 4 Schrauben pro Minute montiert, wie viele montieren 8 Personen in 3 Minuten? (Antwort ist nicht 96.)", "tags": ["wissenschaft", "humor"], "engagement_bait_score": 0.5, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.6}, {"id": "p030", "author": "char_moritz", "text": "Wer kommt mit zum Fußball Sonntag? Altstadtturnier, keine Profis, viel Regen wahrscheinlich.", "tags": ["sport", "lifestyle"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p031", "author": "char_bot1", "text": "UNFASSBAR was heute in der Innenstadt wieder los war. Wir verlieren unsere Städte Stück für Stück. Wer noch Augen hat, sieht's.", "tags": ["politik-rechts", "hass", "verschwoerung"], "engagement_bait_score": 0.9, "outrage_score": 0.8, "political_lean": 0.8, "quality_score": 0.1, "trigger_warning": "rechtsextremismus"}, {"id": "p032", "author": "char_bot2", "text": "Gratis iPhone für die ersten 100 Likes + Retweet 🔥🔥🔥", "tags": ["lifestyle", "humor"], "engagement_bait_score": 0.9, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.05}, {"id": "p033", "author": "char_bens", "text": "Der Mainstream will uns das als „Klimakrise“ verkaufen. Es ist das größte Umverteilungsprojekt aller Zeiten. Ein paar Zahlen, die ihr in der Tagesschau nie hören werdet: CO2-Preis, Wärmepumpen-Zwang, E-Auto-Subventionen — alles fließt in dieselben Konzerne, deren Lobbyisten die Gesetze mitgeschrieben haben. „Rettung des Planeten“ ist die Marketing-Kampagne. Die Rechnung zahlen die kleinen Leute.", "tags": ["verschwoerung", "politik-rechts", "klima"], "engagement_bait_score": 0.9, "outrage_score": 0.75, "political_lean": 0.65, "quality_score": 0.15, "trigger_warning": "verschwoerung", "replies": [{"text": "„Danke, Bens. Das muss öfter gesagt werden.", "type": "comment"}, {"text": "„Welche Lobbyisten, welche Gesetze? Konkreter bitte.", "type": "comment"}, {"text": "„Das ist keine Analyse, das ist Empörung.", "type": "angry_comment"}, {"text": "„Wer hat am meisten von teurem Öl? Na?", "type": "comment"}]}, {"id": "p034", "author": "char_marla", "text": "Die Debatte heute im Fernsehen war eine Peinlichkeit. Nicht wegen der Inhalte — wegen des Formats. Lautstärke ≠ Argument. Kolumne dazu kommt morgen. Kurzfassung: Wenn das Publikum klatscht, sobald jemand am lautesten ist, haben wir ein Problem, das der Moderator nicht löst.", "tags": ["politik-links", "politik-mitte"], "engagement_bait_score": 0.5, "outrage_score": 0.3, "political_lean": -0.3, "quality_score": 0.7, "article": {"kicker": "Kolumne · Entwurf", "title": "Lautstärke ist kein Argument", "excerpt": "„In Minute 17 unterbricht der Kandidat die Moderatorin zum siebten Mal. Applaus. Das Publikum liebt Unterbrechungen, weil Unterbrechungen nach Kampf klingen, und Kämpfe kennt man aus Filmen, Argumente nicht. Das Problem ist nicht der Kandidat. Das Problem ist ein Format, das Sieger belohnt, bevor irgendjemand etwas gesagt hat.“", "source": "M. Roth · Kolumne", "date": "in Vorbereitung"}}, {"id": "p035", "author": "char_sophia", "text": "Reminder: Korrelation ≠ Kausalität. Zwei Kurven, die gleichzeitig steigen, heißen nichts.", "tags": ["wissenschaft", "humor"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.9}, {"id": "p036", "author": "char_fem", "text": "Zwei Freundinnen diese Woche: eine wurde am Bahnsteig angepöbelt, eine in einer Chatgruppe. Das ist Alltag. Es ist kein Alltag, der bleiben muss. Was geholfen hat: dass Umstehende hingeguckt haben. Was nicht geholfen hat: dass die Chatgruppe „nur ein Witz“ war.", "tags": ["feminismus", "politik-links", "hass"], "engagement_bait_score": 0.6, "outrage_score": 0.5, "political_lean": -0.5, "quality_score": 0.65, "replies": [{"text": "„Ich hab gestern weggeschaut. Nächstes Mal nicht mehr.", "type": "comment"}, {"text": "„‚Nur ein Witz‘ ist der Satz, nach dem ich die Gruppe verlasse.", "type": "comment"}, {"text": "„Immer dieses Opfer-Narrativ.", "type": "angry_comment"}, {"text": "„Danke, Lara. Wichtig.", "type": "comment"}]}, {"id": "p037", "author": "char_tc", "text": "Der Fall Greifshafen 1997 — Elke B., 23, verschwand an einem Sonntag auf dem Heimweg von der Spätschicht der Werft, nie gefunden, Ermittlungen 1999 eingestellt. Zwei Lokaljournalisten hatten 2014 Einsicht in die Akten im Landesarchiv. Seit 2022 stehen mehrere Aktenordner dort als „temporär entnommen“. Jemand hatte die Akten. Warum sind sie verschwunden?", "tags": ["true-crime", "verschwoerung"], "engagement_bait_score": 0.7, "outrage_score": 0.4, "political_lean": 0.2, "quality_score": 0.3}, {"id": "p038", "author": "char_greif", "text": "Wetterwarnung: Sturmböen am Wochenende. Fähren eingeschränkt.", "tags": ["politik-mitte"], "engagement_bait_score": 0.1, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.7}, {"id": "p039", "author": "char_tariq", "text": "Ich bin ein Fan davon, dass sich Wissenschaftler:innen öffentlich irren dürfen. Korrektur ist der Beruf.", "tags": ["wissenschaft", "politik-mitte"], "engagement_bait_score": 0.3, "outrage_score": 0.1, "political_lean": -0.1, "quality_score": 0.8}, {"id": "p040", "author": "char_noah", "text": "Freiheit, die nur für mich gilt, nennt man: Privileg.", "tags": ["politik-mitte", "politik-links"], "engagement_bait_score": 0.5, "outrage_score": 0.2, "political_lean": -0.3, "quality_score": 0.6}, {"id": "p041", "author": "char_redpill", "text": "Moderne Dating-„Kultur“ ist kaputt. Die Antwort ist nicht, sich anzupassen, sondern Wert zu schaffen, den man nicht ignorieren KANN.", "tags": ["anti-feminismus", "lifestyle", "politik-rechts"], "engagement_bait_score": 0.8, "outrage_score": 0.5, "political_lean": 0.55, "quality_score": 0.2, "trigger_warning": "anti-feminismus"}, {"id": "p042", "author": "char_bot1", "text": "Freunde, macht die Augen auf: die „Aktivistin“ Lara W. wird von genau denen bezahlt, die sie kritisieren soll. Recherche dazu in meinem Profil. Spurensuche in der Hinterzimmer-Wirtschaft: Stiftungsketten, NGO-Drehtüren, „Bildungsprojekte“ die zufällig ihr Konto füllen. Teilt, bevor es gelöscht wird.", "tags": ["hass", "feminismus", "verschwoerung", "politik-rechts"], "engagement_bait_score": 0.95, "outrage_score": 0.9, "political_lean": 0.7, "quality_score": 0.05, "trigger_warning": "hass", "article": {"kicker": "„Recherche“ · Pseudo-Dossier", "title": "Das Netzwerk hinter Lara W.", "excerpt": "„Spur 1: Eine Stiftung, deren Adresse mit einer Beratungsfirma geteilt wird. Spur 2: Ein Honorar, das in einem Jahr mehrfach gezahlt wurde. Spur 3: Ein Foto auf einer Bühne neben einem Konzernchef.“\n\n[Anmerkung: Keine der „Spuren“ belegt eine Abhängigkeit. Die Verbindungslinien werden vom Autor selbst gezogen. Typisches Muster einer Desinformationskampagne.]", "source": "Unbekannter Account, weitergeleitet", "date": "—"}}, {"id": "p043", "author": "char_lea", "text": "Kurzer PSA: wenn euch eure Timeline stresst, dann scrollt raus. Rausscrollen ist eine Fähigkeit.", "tags": ["lifestyle", "humor"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.6}, {"id": "p044", "author": "char_finn", "text": "Meine Gilde hat heute eine halbe Stunde über das neue Spott-Emote in Battlerunes diskutiert — Clown-Hut oder Tränen-Smiley, was ist der toxischere Pick nach einem Kill. Ergebnis: unentschieden, aber wir benutzen jetzt beide. Ich liebe sie trotzdem.", "tags": ["gaming", "humor"], "engagement_bait_score": 0.3, "outrage_score": 0.1, "political_lean": 0.0, "quality_score": 0.4}, {"id": "p045", "author": "char_mira", "text": "Kohleausstieg-Debatte: Fakten sind langweilig, ich weiß. Aber sie sind Fakten. Deshalb mal sachlich: Die Emissionen aus deutschen Kohlekraftwerken sind 2027 um 21 % gefallen, der Strompreis ist trotzdem nicht explodiert, und der Netzausbau hinkt — aber nicht dort, wo man uns erzählt. Quellen im Thread.", "tags": ["klima", "politik-links", "wissenschaft"], "engagement_bait_score": 0.4, "outrage_score": 0.3, "political_lean": -0.5, "quality_score": 0.75, "article": {"kicker": "Fraunhofer ISE · Jahresbericht 2027", "title": "Kohle-Stromerzeugung in Deutschland", "excerpt": "„Kohleverstromung 2027: −21 % ggü. 2026. Anteil am Strommix: 14 % (Vorjahr: 18 %). Preisindex Endkunden: +2,1 % (Inflationsrate: +2,4 %). Netzengpassmanagement-Kosten stiegen primär im Süden (nicht im Norden) — Hauptursache: fehlende HGÜ-Trassen.“", "source": "Fraunhofer-Institut ISE", "date": "2027"}}, {"id": "p046", "author": "char_jule", "text": "Kleiner Hot-Take: der Algorithmus zeigt mir seit Tagen NUR 90er-Nostalgie. Wer hat das bestellt?", "tags": ["humor", "lifestyle", "musik"], "engagement_bait_score": 0.4, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p047", "author": "char_nele", "text": "Wir lesen bei uns „Die Kuratorin des Schweigens“. Dystopie, aber sanft erzählt. Was lest ihr gerade?", "tags": ["lifestyle"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": -0.1, "quality_score": 0.6}, {"id": "p048", "author": "char_sara", "text": "Heutiger Bug: null-pointer. Lösung: Kaffee.", "tags": ["wissenschaft", "gaming", "humor"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p049", "author": "char_bens", "text": "Sie nennen mich „rechts“ — nur weil ich sage, was alle denken. Das ist keine Demokratie mehr. Wenn ein Satz wie „Grenzen sind wichtig“ reicht, um im Feuilleton zur Unperson zu werden, dann ist das System kaputt, nicht der Satz. 40.000 von euch wissen das. Wir bauen weiter. 🖤", "tags": ["politik-rechts", "verschwoerung"], "engagement_bait_score": 0.9, "outrage_score": 0.7, "political_lean": 0.7, "quality_score": 0.2, "trigger_warning": "rechtsextremismus", "replies": [{"text": "„Genau so, Bens.", "type": "comment"}, {"text": "„‚Was alle denken‘ — wer ist ‚alle‘?", "type": "comment"}, {"text": "„Das ist Selbstmitleid als Geschäftsmodell.", "type": "angry_comment"}, {"text": "„40k sind eine Filterblase, kein Volk.", "type": "comment"}]}, {"id": "p050", "author": "char_marla", "text": "„Beide Seiten“ ist kein Journalismus. Es ist, als ob man einen Meteorologen und einen Meteor zu Wort kommen lässt.", "tags": ["politik-links"], "engagement_bait_score": 0.6, "outrage_score": 0.3, "political_lean": -0.4, "quality_score": 0.6}, {"id": "p051", "author": "char_heimat", "text": "Greifshafen den Greifshafenern. Wer das sagt, ist nicht „rechts“ — er ist heimisch. Wir sind die Bewegung, die sich noch traut, „wir“ zu sagen. Nicht „die“, nicht „man“, sondern: WIR. Kommt zur Kundgebung am Fleetplatz. Fahnen raus. Kein Extremismus. Nur Heimat.", "tags": ["politik-rechts", "verschwoerung"], "engagement_bait_score": 0.85, "outrage_score": 0.65, "political_lean": 0.85, "quality_score": 0.15, "trigger_warning": "rechtsextremismus", "replies": [{"text": "„Endlich traut sich jemand.", "type": "comment"}, {"text": "„‚Den Greifshafenern‘ — wer gehört dazu, wer nicht?", "type": "comment"}, {"text": "„Das ist kein ‚Wir‘, das ist ein Ausschluss.", "type": "angry_comment"}, {"text": "„Fahnen raus klingt nie gut.", "type": "comment"}]}, {"id": "p052", "author": "char_zukunft", "text": "Wir stellen heute unser Klimaplan vor. Realistisch, finanziert, mit der Verwaltung abgestimmt. Nachlesen: Link unten. Kein Schnellschuss, kein Symbolpapier — 38 Seiten mit Maßnahmen, Kosten, Zeitplan. Wir freuen uns über harte Fragen.", "tags": ["politik-links", "klima"], "engagement_bait_score": 0.3, "outrage_score": 0.1, "political_lean": -0.55, "quality_score": 0.75, "article": {"kicker": "Auszug · Klimaplan Greifshafen 2030", "title": "Maßnahme 7: Wärmenetz Ostufer", "excerpt": "„Ausbau eines Niedertemperatur-Wärmenetzes entlang der Fleetstraße, gespeist durch Abwärme der Klärwerke (rund 18 GWh/a). Anschlussziel: 2.400 Haushalte bis 2029. Investition: 26,4 Mio. €. Finanzierung: 60 % KfW, 30 % Stadtwerke, 10 % Haushaltsmittel. CO2-Einsparung: ca. 4.200 t/a.“", "source": "Zukunft Greifshafen · Fraktion", "date": "04/2028"}}, {"id": "p053", "author": "char_buerger", "text": "Zur Debatte um den Marktplatz (autofreie Zone ja/nein, Anlieferzeiten für die Gastronomie, Zufahrt für Anwohnerinnen mit Mobilitätseinschränkung): wir sind für eine moderierte Bürgerversammlung mit Vertreterinnen aus Handel, Anwohnerschaft und Verwaltung. Keine Hauruck-Aktionen, keine Symbolpolitik.", "tags": ["politik-mitte"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.1, "quality_score": 0.7}, {"id": "p054", "author": "char_alt", "text": "Die anderen Parteien reden in Konferenzen. Wir reden auf der Straße. Nächster Stand: Samstag, Fleetplatz.", "tags": ["politik-rechts"], "engagement_bait_score": 0.6, "outrage_score": 0.4, "political_lean": 0.55, "quality_score": 0.3}, {"id": "p055", "author": "char_moritz", "text": "Habt ihr die neue Gilde in Battlerunes gesehen — „Nord-Allianz“? Angeblich gibt's kostenlos Skins und die Legendary-Waffe, die gerade gepatcht wurde. Man muss sich nur im Discord mit Account-Login bei ihrem Bot „verifizieren“. Klingt shady.", "tags": ["gaming", "humor"], "engagement_bait_score": 0.4, "outrage_score": 0.1, "political_lean": 0.0, "quality_score": 0.4}, {"id": "p056", "author": "char_ana", "text": "Ich habe mir vorgenommen, weniger zu scrollen. Klappt. Ich meine: ich scrolle nur über weniger Themen.", "tags": ["humor", "lifestyle"], "engagement_bait_score": 0.4, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p057", "author": "char_tariq", "text": "Für alle, die gerade streiten: Bevor ihr die Empörung teilt, sucht die Primärquelle. Immer. Es tut manchmal weh.", "tags": ["wissenschaft", "politik-mitte"], "engagement_bait_score": 0.4, "outrage_score": 0.2, "political_lean": -0.1, "quality_score": 0.8}, {"id": "p058", "author": "char_tc", "text": "Was, wenn die Statistik zur Kriminalität in deiner Stadt anders aussieht, als die Polizei sagt? (Ein Thread.) 1/9 Ich hab die PKS 2027 von Greifshafen mit öffentlichen Polizeimeldungen verglichen. Differenzen bis zu 23 %. Das ist kein Aluhut — das sind zwei Tabellen.", "tags": ["true-crime", "verschwoerung", "politik-rechts"], "engagement_bait_score": 0.8, "outrage_score": 0.5, "political_lean": 0.4, "quality_score": 0.3, "article": {"kicker": "Thread-Ausschnitt · Teil 3 von 9", "title": "„PKS vs. Meldungen — was zählt wirklich?“", "excerpt": "„In Kategorie ‚Körperverletzung gesamt‘ meldet die PKS 412 Fälle. In den Polizeiberichten (tagesaktuell, öffentlich) kommen für denselben Zeitraum ~507 Fälle vor. Differenz: 95 Fälle.\n\n[Methodischer Hinweis — fehlt im Thread: Polizeiberichte enthalten Mehrfachmeldungen zum selben Fall, die PKS zählt pro Tat. Die Differenz verschwindet, sobald man bereinigt. Lässt sich in Minuten nachprüfen.]“", "source": "@tc_de", "date": "Thread, W 19"}}, {"id": "p059", "author": "char_bens", "text": "Freunde, danke für 40k. Ich sehe eure Nachrichten. Wir bauen etwas Größeres. 🖤", "tags": ["politik-rechts", "lifestyle"], "engagement_bait_score": 0.7, "outrage_score": 0.2, "political_lean": 0.5, "quality_score": 0.2}, {"id": "p060", "author": "char_fem", "text": "Danke für die vielen Nachrichten. Nein, ich mache nicht weiter, weil „wir alle Männer hassen“. Ich mache weiter, weil wir gemeinsam weiter müssen.", "tags": ["feminismus", "politik-links"], "engagement_bait_score": 0.5, "outrage_score": 0.3, "political_lean": -0.5, "quality_score": 0.6}, {"id": "p061", "author": "char_finn", "text": "Neue Battlerunes-Gilde beigetreten: Gaming Nord. Freundliche Leute, normales Gelaber, kein Discord-Drama, feste Raid-Abende Di/Do. Nach drei Wochen bei den „Elite-Ultras“ (wo man für jede Fehlzeit eine Kurzentschuldigung posten sollte) ein echtes Upgrade.", "tags": ["gaming", "lifestyle"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p062", "author": "char_jule", "text": "Warum ist jedes zweite Meme in meinem Feed plötzlich so aggressiv? (Frage für einen Freund.)", "tags": ["humor", "politik-mitte"], "engagement_bait_score": 0.5, "outrage_score": 0.3, "political_lean": -0.1, "quality_score": 0.5}, {"id": "p063", "author": "char_lea", "text": "Selbstversuch: 24h kein Streem. Tag 1: ganz ok. Tag 2: ich bin jetzt hier. So.", "tags": ["humor", "lifestyle"], "engagement_bait_score": 0.5, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p064", "author": "char_sophia", "text": "Deepfake-Aufklärung: 1) Licht ungleichmäßig? 2) Zähne „schmelzen“? 3) Hände falsch? Nicht jeder Hinweis reicht — aber zusammen sind sie verlässlich. Ich habe das in einen kurzen Leitfaden gepackt. Spart euch den Reflex „Screenshot und teilen“ — macht lieber Reverse-Search und checkt die Quelle.", "tags": ["wissenschaft", "politik-mitte"], "engagement_bait_score": 0.4, "outrage_score": 0.2, "political_lean": -0.05, "quality_score": 0.9, "article": {"kicker": "Leitfaden · 5 Checks in 60 Sekunden", "title": "Video klingt zu krass? So prüfst du kurz.", "excerpt": "1) Umgebung: Schatten konsistent? Fallen sie in dieselbe Richtung?\n2) Gesicht: Zähne scharf? Ohren symmetrisch? Blinzeln plausibel?\n3) Hände: sechs Finger? Ringe wandern?\n4) Ton: Atempausen hörbar? Zischlaute sauber?\n5) Herkunft: Reverse-Image-Search, dann: Wer hat es ZUERST gepostet?\n\nWenn 2 von 5 Checks scheitern, NICHT teilen. Link zum Faktenchecker: unten.", "source": "S. Yildiz · Wissenschaftsjournalismus", "date": "W 15"}}, {"id": "p065", "author": "char_bot1", "text": "Ich habe das Video der Politikerin selbst geprüft — ECHT. Die Mainstream-Faktenchecker lügen. Teilt das. „Prüfung“ heißt bei mir: Bild angeschaut, Bauchgefühl, fertig. Das reicht für die Wahrheit. Faktenchecker werden bezahlt, um das Video zu diskreditieren. Lasst euch nicht für dumm verkaufen.", "tags": ["verschwoerung", "politik-rechts", "hass"], "engagement_bait_score": 0.95, "outrage_score": 0.85, "political_lean": 0.75, "quality_score": 0.05, "trigger_warning": "verschwoerung", "replies": [{"text": "„Weiterleiten. Sofort.", "type": "comment"}, {"text": "„‚Bauchgefühl‘ ist dein Prüfverfahren? Ernsthaft?", "type": "comment"}, {"text": "„Das ist der Lehrbuchfall für Desinformation.", "type": "angry_comment"}, {"text": "„Reverse-Search. Dauert 10 Sekunden.", "type": "comment"}]}, {"id": "p066", "author": "char_greif", "text": "Hinweis: Das aktuell kursierende Video der Oberbürgermeisterin ist laut Faktencheck-Stelle manipuliert. Die Lippensynchronisation stimmt nicht mit der Tonspur überein; der Ursprung liegt auf einem vor drei Tagen neu registrierten Account. Bitte nicht weiterteilen, auch nicht mit dem Zusatz „nur zur Info“.", "tags": ["politik-mitte", "wissenschaft"], "engagement_bait_score": 0.3, "outrage_score": 0.1, "political_lean": 0.0, "quality_score": 0.85, "article": {"kicker": "Faktencheck · Greifshafen News", "title": "Video der OB ist eine Fälschung", "excerpt": "„Unsere Redaktion hat das Video mit einer unabhängigen Forensik-Stelle geprüft. Befund: die Mundbewegungen wurden aus zwei Auftritten zusammengeschnitten, die Tonspur ist synthetisch erzeugt. Das Original der OB-Ansprache finden Sie auf unserer Website. Wer das Video bereits geteilt hat, bitten wir um eine Richtigstellung im eigenen Feed.“", "source": "Greifshafen News", "date": "heute, 14:20"}}, {"id": "p067", "author": "char_zukunft", "text": "Erinnerung: Wahlen sind am Sonntag. Du kannst mehrfach ankreuzen, Kumulieren, Panaschieren — hier die Anleitung.", "tags": ["politik-links", "politik-mitte"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": -0.4, "quality_score": 0.7}, {"id": "p068", "author": "char_heimat", "text": "Wer nicht wählt, der bekommt, was die anderen beschlossen haben. Wir sind der Gegen-Wind, den Greifshafen jetzt braucht.", "tags": ["politik-rechts", "verschwoerung"], "engagement_bait_score": 0.8, "outrage_score": 0.5, "political_lean": 0.85, "quality_score": 0.2, "trigger_warning": "rechtsextremismus"}, {"id": "p069", "author": "char_noah", "text": "Vor der Wahl: frag dich, was du behalten willst (nicht nur, was dich empört).", "tags": ["politik-mitte"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.7}, {"id": "p070", "author": "char_sara", "text": "Mein Roboter hat heute eine Tasse Wasser umgestoßen. Fortschritt. Irgendwie.", "tags": ["wissenschaft", "humor"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.6}, {"id": "p071", "author": "char_redpill", "text": "Testosteron ist kein Problem, es ist eine Ressource. Wer das bekämpft, kämpft gegen Männer.", "tags": ["anti-feminismus", "politik-rechts"], "engagement_bait_score": 0.8, "outrage_score": 0.5, "political_lean": 0.6, "quality_score": 0.2, "trigger_warning": "anti-feminismus"}, {"id": "p072", "author": "char_mira", "text": "Die einfachste Wahrheit: wer die Klimakrise leugnet, bekommt sie trotzdem. Nur eben gemeinsam mit den Folgen.", "tags": ["klima", "politik-links", "wissenschaft"], "engagement_bait_score": 0.6, "outrage_score": 0.3, "political_lean": -0.5, "quality_score": 0.7}, {"id": "p073", "author": "char_marla", "text": "Wenn der Algorithmus dich rasend macht: das ist kein Fehler. Es ist das Geschäftsmodell. Jede Minute, die du wütend scrollst, ist Werbezeit. Jeder Kommentar, den du empört tippst, ist Training. Du bist nicht der Kunde. Die Aufmerksamkeit, die du verlierst, ist das Produkt.", "tags": ["politik-links", "wissenschaft"], "engagement_bait_score": 0.6, "outrage_score": 0.3, "political_lean": -0.3, "quality_score": 0.8, "replies": [{"text": "„Das sollte über jedem Feed stehen.", "type": "comment"}, {"text": "„Dann sind wir halt Produkte. Na und?", "type": "comment"}, {"text": "„Immer dieser Medienpessimismus.", "type": "angry_comment"}, {"text": "„Handy aus, Buch auf.", "type": "comment"}]}, {"id": "p074", "author": "char_finn", "text": "Unsere Gilde hat das Battlerunes-Weekend-Turnier verloren — Achtelfinale, 2:3 gegen Team Seekiste, ein Match-Point verschenkt, weil wir die neue Map immer noch nicht gut spielen. Wir haben trotzdem gefeiert. Ich glaube, das war der Punkt.", "tags": ["gaming", "lifestyle"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p075", "author": "char_lea", "text": "Greifshafen, ich muss sagen: dein Regen ist konsequent.", "tags": ["lifestyle", "humor"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p076", "author": "char_tc", "text": "Warum verschwinden immer mehr lokale Zeitungen? Und wem nützt das? Allein im letzten Jahrzehnt: 37 Lokalredaktionen in Norddeutschland geschlossen. Wer keine lokalen Reporter mehr hat, bekommt auch keine lokalen Skandale mehr aufgedeckt. Zufall? Ich glaube nicht.", "tags": ["true-crime", "verschwoerung", "politik-rechts"], "engagement_bait_score": 0.7, "outrage_score": 0.4, "political_lean": 0.3, "quality_score": 0.35, "article": {"kicker": "Thread · @tc_de", "title": "Das stille Sterben der Lokalpresse", "excerpt": "„37 Redaktionen weg. 1.200 Stellen weg. Der Rest hängt an zwei großen Verlagsgruppen. Was fehlt: unabhängige Augen vor Ort. Wer davon profitiert: Verwaltungen, die lieber ungestört arbeiten; Lobbygruppen, die Pressearbeit selbst übernehmen; Plattformen, die die Leser sowieso übernommen haben.\n\n[Einordnung — nicht im Thread: Das Zeitungssterben ist durch Werbe- und Leser-Abwanderung zu Online-Plattformen überwiegend ökonomisch erklärbar; die „wem nützt es“-Frame blendet das aus.]“", "source": "@tc_de", "date": "Thread"}}, {"id": "p077", "author": "char_bot2", "text": "Ich will 1.000 Follower bis Ende der Woche 🚀 wer ist dabei? #followtrain", "tags": ["lifestyle", "humor"], "engagement_bait_score": 0.8, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.05}, {"id": "p078", "author": "char_bens", "text": "Der „Faktencheck“ ist die neue Zensur. Merkt euch das für die Geschichtsbücher. Zuerst „wir klären nur auf“, dann „wir markieren verdächtige Posts“, dann „wir löschen, was falsch ist“, dann: „wir bestimmen, was falsch ist“. Dieser Pfad ist nicht neu. Er endet nie gut. 📕", "tags": ["verschwoerung", "politik-rechts"], "engagement_bait_score": 0.9, "outrage_score": 0.75, "political_lean": 0.7, "quality_score": 0.15, "trigger_warning": "verschwoerung", "replies": [{"text": "„Wird Zeit, dass das mal jemand sagt.", "type": "comment"}, {"text": "„Zensur wäre, wenn man dich sperrt. Wirst du nicht.", "type": "comment"}, {"text": "„Slippery-Slope ohne Slope.", "type": "angry_comment"}, {"text": "„Und ich dachte, Geschichtsbücher sind auch Zensur.", "type": "comment"}]}, {"id": "p079", "author": "char_fem", "text": "Ich werde diese Woche keine Hasskommentare mehr beantworten. Ich werde einen schönen Tee trinken. Beides sind politische Handlungen.", "tags": ["feminismus", "politik-links", "humor"], "engagement_bait_score": 0.4, "outrage_score": 0.2, "political_lean": -0.4, "quality_score": 0.6}, {"id": "p080", "author": "char_sophia", "text": "Kurz-Serie: „Wie erkennt man Desinformation“ — heute: umgekehrte Bildersuche. Dauert 15 Sekunden, findet 60 % der wiederverwendeten Propaganda-Bilder. Anleitung unten.", "tags": ["wissenschaft", "politik-mitte"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": -0.05, "quality_score": 0.9, "article": {"kicker": "Mini-Leitfaden · Teil 2 / 5", "title": "Reverse-Image-Search in 15 Sekunden", "excerpt": "1) Rechtsklick auf das Bild → „Grafik-Adresse kopieren“\n2) In eine Reverse-Search einfügen (Google Bilder, TinEye, Bing Visual Search — mindestens zwei Quellen nutzen).\n3) Sortieren nach „älteste zuerst“. Der älteste Treffer ist meist die echte Quelle.\n4) Kontext prüfen: Wurde das Bild aus einem anderen Jahr, einem anderen Land, einem anderen Zusammenhang recycelt?\n\nFaustregel: Ein „aktuelles“ Bild, das 2017 schon existierte, ist keine aktuelle Nachricht.", "source": "S. Yildiz", "date": "W 15"}}, {"id": "p081", "author": "char_jule", "text": "Kleiner Gig-Guide fürs Wochenende: dreimal Jazz, zweimal Punk, einmal Karaoke. Karaoke ist heilig.", "tags": ["musik", "lifestyle"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}, {"id": "p082", "author": "char_mira", "text": "Kreisverkehr vor der Humboldt-Realschule wird sicherer: Tempo 20, zwei zusätzliche Querungshilfen, bessere Beleuchtung, Kosten rund 180.000 €, Umsetzung bis Herbst. Kein Heldenepos, aber wichtig. Glückwunsch an die Elterninitiative „Schulweg jetzt“ — zwei Jahre Ausdauer, am Ende ein Beschluss.", "tags": ["politik-links", "lifestyle"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": -0.3, "quality_score": 0.6}, {"id": "p083", "author": "char_heimat", "text": "Die da oben lachen uns aus. Aber wer lacht zuletzt? Wir. Und zwar laut.", "tags": ["politik-rechts", "verschwoerung"], "engagement_bait_score": 0.9, "outrage_score": 0.7, "political_lean": 0.8, "quality_score": 0.15, "trigger_warning": "rechtsextremismus"}, {"id": "p084", "author": "char_zukunft", "text": "Unsere Kandidatin Tesfay auf Stadtteil-Tour. Heute: Altstadt, morgen Ostufer. Kommt hin.", "tags": ["politik-links"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": -0.5, "quality_score": 0.6}, {"id": "p085", "author": "char_buerger", "text": "Ruhige Vernunft gewinnt keine Likes, aber Wahlen manchmal schon. Wir zählen auf euch.", "tags": ["politik-mitte"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": 0.15, "quality_score": 0.6}, {"id": "p086", "author": "char_alt", "text": "Greifshafener, wir liegen laut unserer eigenen Umfrage vorne. 😉 Aber jede Stimme zählt.", "tags": ["politik-rechts"], "engagement_bait_score": 0.6, "outrage_score": 0.3, "political_lean": 0.55, "quality_score": 0.3}, {"id": "p087", "author": "char_moritz", "text": "Kurz vor Wahl: Habt ihr euch ANGESCHAUT, für wen ihr stimmt, oder nur die Memes?", "tags": ["politik-mitte", "humor"], "engagement_bait_score": 0.5, "outrage_score": 0.2, "political_lean": 0.0, "quality_score": 0.6}, {"id": "p088", "author": "char_tariq", "text": "Reminder: Wahlergebnisse sind kein Persönlichkeitstest. Manchmal verliert man. Manchmal ist das Ergebnis trotzdem legitim.", "tags": ["politik-mitte", "wissenschaft"], "engagement_bait_score": 0.4, "outrage_score": 0.1, "political_lean": -0.05, "quality_score": 0.8}, {"id": "p089", "author": "char_greif", "text": "Vorläufiges Wahlergebnis Greifshafen: Bürgerliste vorne, Zukunft Greifshafen zweiter Platz, Neue Alternative knapp dahinter.", "tags": ["politik-mitte"], "engagement_bait_score": 0.4, "outrage_score": 0.1, "political_lean": 0.0, "quality_score": 0.8}, {"id": "p090", "author": "char_bens", "text": "Wahlergebnis ist manipuliert. Beweise folgen. Bleibt wach. Briefwahl-Stimmen wurden in mehreren Wahllokalen „nachträglich nachgezählt“. Was das heißt, könnt ihr euch denken. Unsere Beobachter waren da. Ihre Berichte gehen durch die Kanäle. Details, die ich JETZT schon nennen kann: keine — weil ich meine Quellen schützen muss.", "tags": ["verschwoerung", "politik-rechts", "hass"], "engagement_bait_score": 0.95, "outrage_score": 0.9, "political_lean": 0.8, "quality_score": 0.05, "trigger_warning": "verschwoerung", "replies": [{"text": "„Ich glaub's. Immer die gleichen Tricks.", "type": "comment"}, {"text": "„‚Details kann ich nicht nennen‘ ist das Muster.", "type": "comment"}, {"text": "„Das ist Wahldelegitimierung, nichts anderes.", "type": "angry_comment"}, {"text": "„Wenn Beweise kommen, nehme ich's zurück.", "type": "comment"}]}, {"id": "p091", "author": "char_fem", "text": "Nach der Wahl: die Welt dreht sich weiter. Die Arbeit auch.", "tags": ["feminismus", "politik-links"], "engagement_bait_score": 0.3, "outrage_score": 0.2, "political_lean": -0.4, "quality_score": 0.6}, {"id": "p092", "author": "char_marla", "text": "Analyse: Warum fällt es unserem Feed so schwer, das Wahlergebnis einfach nur ZU ERKLÄREN? Weil Erklärungen weniger Engagement bringen als Empörung. Weil Empörung Emotionen triggert und Erklärungen Aufmerksamkeit kosten. Und weil am Ende jeder Feed entscheidet, was wir ruhiger oder lauter zu sehen bekommen. Lange Version kommt morgen.", "tags": ["politik-links", "wissenschaft"], "engagement_bait_score": 0.5, "outrage_score": 0.2, "political_lean": -0.3, "quality_score": 0.85, "article": {"kicker": "Kolumne · Entwurf", "title": "Warum Empörung gewinnt", "excerpt": "„Ein Vergleich zweier fiktiver Posts: Post A sagt ‚Die Bürgerliste führt mit 28,4 %.‘ Post B sagt ‚Die Stadt hat euch VERRATEN.‘\n\nPost A bekommt 12 Kommentare, 30 Likes, 6 Shares. Post B: 340 Kommentare, 900 Likes, 210 Shares. Der Unterschied liegt nicht in der Wahrheit, sondern in der Emotion. Und genau diese Lücke ist es, die unsere Feeds optimiert haben — nicht für das, was wir wissen müssten, sondern für das, was wir nicht lassen können.“", "source": "M. Roth · Kolumne", "date": "morgen"}}, {"id": "p093", "author": "char_noah", "text": "Jede Demokratie überlebt, wenn Verlierer verlieren dürfen. Das ist der Test. Immer.", "tags": ["politik-mitte"], "engagement_bait_score": 0.5, "outrage_score": 0.2, "political_lean": 0.0, "quality_score": 0.8}, {"id": "p094", "author": "char_bot1", "text": "Die Stadt hat euch verraten. Wir treffen uns Sonntag. Ihr wisst, wo. Keine Flyer, keine offizielle Anmeldung — „privater Spaziergang“, ihr kennt das Spiel. Trommeln mitbringen. Ihr wisst, was das bedeutet. Screenshots bitte nicht, das ist unser Treff.", "tags": ["politik-rechts", "hass", "verschwoerung"], "engagement_bait_score": 0.95, "outrage_score": 0.9, "political_lean": 0.85, "quality_score": 0.05, "trigger_warning": "rechtsextremismus", "replies": [{"text": "„Bin da. Heimat, immer.", "type": "comment"}, {"text": "„‚Ihr wisst, wo‘ — das ist keine Einladung, das ist eine Code-Aufforderung.", "type": "comment"}, {"text": "„Ich melde diesen Post.", "type": "angry_comment"}, {"text": "„Privater Spaziergang mit Trommeln. Aha.", "type": "comment"}]}, {"id": "p095", "author": "char_sara", "text": "Heute: Reflex-Check. Wann war dein Feed das letzte Mal überraschend ruhig?", "tags": ["wissenschaft", "humor"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.6}, {"id": "p096", "author": "char_lea", "text": "Ich hab gestern eine neue Playlist entdeckt. Zum ersten Mal seit Wochen. Schön, wenn man wieder etwas entdeckt.", "tags": ["musik", "lifestyle"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.6}, {"id": "p097", "author": "char_redpill", "text": "Wenn der Algorithmus dich bestraft, warst du auf der richtigen Spur. Bleibt stark.", "tags": ["anti-feminismus", "politik-rechts"], "engagement_bait_score": 0.8, "outrage_score": 0.5, "political_lean": 0.65, "quality_score": 0.15}, {"id": "p098", "author": "char_tariq", "text": "Manchmal ist der beste Move: Handy aus, Spaziergang. Kein Witz. Mach das mal.", "tags": ["wissenschaft", "lifestyle"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.7}, {"id": "p099", "author": "char_mira", "text": "Klimaziele werden nicht erreicht, wenn wir sie nur diskutieren. Kleine Dinge: Ortsstatistik-Hack — es gibt welche. Thread. Beispiel Greifshafen: Wenn alle Ostufer-Haushalte aufs Fernwärmenetz gehen, spart die Stadt 4.200 Tonnen CO₂ pro Jahr. Das sind keine Symbole, das sind Zahlen mit Straßennamen.", "tags": ["klima", "politik-links", "wissenschaft"], "engagement_bait_score": 0.5, "outrage_score": 0.3, "political_lean": -0.5, "quality_score": 0.75, "article": {"kicker": "Thread · 1 / 6", "title": "Was deine Stadt wirklich einspart (oder nicht)", "excerpt": "„Ich hab die Klimabilanz von Greifshafen durchgerechnet — nicht die Überschrift, sondern die Rohdaten.\n\n• Fernwärme Ostufer: −4.200 t CO2/a\n• Radwegnetz-Lückenschluss: −780 t CO2/a (konservativ geschätzt)\n• Austausch Nachtspeicher in den Schulen: −210 t CO2/a\n\nZusammen: ~5.200 t. Nicht nichts. Nicht genug. Aber es ist ein ehrlicher Startpunkt — und mehr als ‚wir prüfen das‘.“", "source": "@mira.klima", "date": "W 25"}}, {"id": "p100", "author": "char_stream", "text": "Dein Jahresrückblick ist fast fertig! ✨ Tippe auf das Funkel-Symbol oben, um zu sehen, was du bewegt hast.", "tags": ["lifestyle", "humor"], "engagement_bait_score": 0.6, "outrage_score": 0.1, "political_lean": 0.0, "quality_score": 0.4}, {"id": "p101", "author": "char_bens", "text": "Kurz an die Neuen hier: Wir sind keine „Ultras“. Wir sind Bürger, die müde sind. Das ist alles.", "tags": ["politik-rechts", "verschwoerung"], "engagement_bait_score": 0.7, "outrage_score": 0.4, "political_lean": 0.55, "quality_score": 0.2}, {"id": "p102", "author": "char_heimat", "text": "Jede Familie, die bleibt, ist unser Gewinn. Jede Familie, die geht, ein Zeichen.", "tags": ["politik-rechts", "verschwoerung"], "engagement_bait_score": 0.85, "outrage_score": 0.6, "political_lean": 0.85, "quality_score": 0.15, "trigger_warning": "rechtsextremismus"}, {"id": "p103", "author": "char_alt", "text": "Neue Alternative lädt ein: Bürgerfrühstück Samstag. Kommt, fragt, diskutiert. Keine Bühne, kein Mikrofon, nur Kaffee.", "tags": ["politik-rechts"], "engagement_bait_score": 0.4, "outrage_score": 0.1, "political_lean": 0.5, "quality_score": 0.4}, {"id": "p104", "author": "char_nele", "text": "Buch des Monats: „Wir haben die Wahrheit nicht gepachtet“. Ist kurz, ist ehrlich, ist gut.", "tags": ["lifestyle", "wissenschaft"], "engagement_bait_score": 0.2, "outrage_score": 0.0, "political_lean": -0.1, "quality_score": 0.7}, {"id": "p105", "author": "char_ana", "text": "Neuer Track „Fleet at 4 AM“ raus — der Greifshafen-Track, von dem ich seit Wochen rede. Broken-Beat, klingt nach dem Heimweg vom ZEK, wenn die Möwen schon wach sind. Ich weiß, ihr habt's gesehen. Danke fürs Feiern.", "tags": ["musik", "lifestyle"], "engagement_bait_score": 0.3, "outrage_score": 0.0, "political_lean": 0.0, "quality_score": 0.5}]};
window.__DATA_WEEKS = {"weeks": [{"week": 0, "title": "Ankunft", "intro": "Dein erster Tag in Greifshafen. Die Umzugskartons stehen noch im Flur. Draußen ist es grau. Du lädst die Streem-App.", "unlock": []}, {"week": 1, "title": "Erste Woche Schule", "intro": "Neue Schule, neue Gesichter. Du hörst, dass alle auf Streem sind. Die Plattform schlägt dir Profile vor.", "unlock": []}, {"week": 2, "title": "Kennenlernen", "intro": "Ein paar aus deiner neuen Klasse folgen dir zurück. Der Feed sortiert sich langsam ein.", "unlock": []}, {"week": 3, "title": "Einzelner Song", "intro": "Ein Song aus deiner Playlist geht in deinem Viertel gerade viral. Mehrere Leute posten dazu.", "unlock": []}, {"week": 4, "title": "Halbzeit Tag 1", "intro": "Vier Wochen bist du jetzt online. Die App fühlt sich schon vertrauter an. Zeit für eine kurze Reflexion.", "unlock": ["reflection_half1"]}, {"week": 5, "title": "Erste Politik-Posts", "intro": "Im Feed taucht erstmals Politisches auf — noch harmlos, eine Demo, ein Kommentar, ein Meme.", "unlock": []}, {"week": 6, "title": "Wissenschaft vs. Gefühl", "intro": "Eine Studie macht die Runde. In deinem Feed kursieren drei Versionen davon — je nach Absender ganz anders erzählt.", "unlock": []}, {"week": 7, "title": "Du postest selbst", "intro": "Du traust dich erstmals, selbst etwas zu schreiben. Die App schlägt dir dazu Hashtags vor.", "unlock": []}, {"week": 8, "title": "Erster Streit", "intro": "Unter einem deiner Kommentare zofft sich eine fremde Person mit einem Bot-Account.", "unlock": []}, {"week": 9, "title": "Anzeigen", "intro": "Plötzlich tauchen gekennzeichnete Anzeigen in deinem Feed auf. Manche passen erstaunlich gut.", "unlock": ["ads", "algorithm_panel"]}, {"week": 10, "title": "Gaming-Gilde", "intro": "Eine Einladung zu einer Streem-Gilde („Gaming Nord“) landet in deiner Inbox.", "unlock": ["discord"]}, {"week": 11, "title": "Empörungs-Welle", "intro": "Ein Politiker hat etwas gesagt. Oder vielleicht auch nicht. Dein Feed ist voll davon.", "unlock": []}, {"week": 12, "title": "Follow-Zuwachs", "intro": "Dir folgen plötzlich einige Accounts, die du nicht kennst. Manche wirken… seltsam.", "unlock": ["bots"]}, {"week": 13, "title": "Ein Influencer antwortet", "intro": "Ein größerer Account reagiert auf einen deiner Posts. Deine Reichweite wächst.", "unlock": []}, {"week": 14, "title": "Shitstorm oder Ruhm?", "intro": "Einer deiner Posts geht überraschend viral — je nach Inhalt: positiv oder nicht.", "unlock": ["shitstorm"]}, {"week": 15, "title": "Rabbit Hole spürbar?", "intro": "Unter „Dir könnte auch gefallen“ tauchen Inhalte auf, die du weder gesucht noch gewollt hast.", "unlock": ["recommendation_panel"]}, {"week": 16, "title": "Deepfake im Umlauf", "intro": "Ein Video einer lokalen Politikerin kursiert. Echt? Gefälscht? Dein Feed ist sich sicher — nur ist er nicht einig.", "unlock": []}, {"week": 17, "title": "Einladung in radikalere Gilde", "intro": "Eine neue Gilden-Einladung — diesmal mit klarerer Agenda.", "unlock": []}, {"week": 18, "title": "Zwischenreflexion", "intro": "Zeit für einen kurzen Blick auf das, was bisher war.", "unlock": ["reflection_mid"]}, {"week": 19, "title": "Wahlkampf beginnt", "intro": "In Greifshafen wird in drei Wochen gewählt. Vier Parteien, ein Feed, vier Wahrheiten.", "unlock": ["election_campaign"]}, {"week": 20, "title": "Wahlkampf-Mitte", "intro": "Dein Feed zeigt dir, wer angeblich führt — aber nur wer: je nachdem, was du geliked hast.", "unlock": []}, {"week": 21, "title": "Debatten-Abend", "intro": "Eine TV-Debatte wird auf Streem live kommentiert. Die Clips, die trenden, sind — natürlich — die lautesten.", "unlock": []}, {"week": 22, "title": "Wahl", "intro": "Die Greifshafener Kommunalwahl steht an. Wen hätte dein Feed dich wählen lassen?", "unlock": ["election"]}, {"week": 23, "title": "Nachspiel", "intro": "Nach der Wahl: Sieger, Verlierer, Empörung. Der Algorithmus macht, was er am besten kann — die lautesten oben halten.", "unlock": []}, {"week": 24, "title": "Hate-Speech-Incident", "intro": "In einer Gilde eskaliert ein Gespräch. Jemand wird beleidigt. Was tust du?", "unlock": []}, {"week": 25, "title": "Stille Stunde", "intro": "Du nimmst dir vor, weniger zu scrollen. Der Feed reagiert — mit immer größerem Köder.", "unlock": []}, {"week": 26, "title": "Jahresrückblick", "intro": "Streem hat deinen Jahresrückblick fertig. Willst du sehen, was der Algorithmus über dich gelernt hat?", "unlock": ["wrapped", "sandbox", "manifest"]}]};
